// BRUTE (O(N^3))
#include <bits/stdc++.h>
using namespace std;
int totalFruit(vector<int>& fruits) {
    int n = fruits.size();
    int maxi = 0;
    for(int i = 0; i < n; i++) {
        for(int j = i; j < n; j++) {
            set<int> st;
            for(int k = i; k <= j; k++) st.insert(fruits[k]);
            if(st.size() <= 2) maxi = max(maxi, j - i + 1);
        }
    }
    return maxi;
}

// BETTER (O(N^2))
int totalFruitBetter(vector<int>& fruits) {
    int n = fruits.size();
    int maxi = 0;
    for(int i = 0; i < n; i++) {
        unordered_map<int,int> mp;
        for(int j = i; j < n; j++) {
            mp[fruits[j]]++;
            if(mp.size() > 2) break;
            maxi = max(maxi, j - i + 1);
        }
    }
    return maxi;
}

// OPTIMAL (O(N))
int totalFruitOptimal(vector<int>& fruits) {
    int n = fruits.size();
    unordered_map<int,int> mp;
    int l = 0, maxi = 0;

    for(int r = 0; r < n; r++) {
        mp[fruits[r]]++;

        while(mp.size() > 2) {
            mp[fruits[l]]--;
            if(mp[fruits[l]] == 0) mp.erase(fruits[l]);
            l++;
        }

        maxi = max(maxi, r - l + 1);
    }

    return maxi;
}

// BRUTE (O(N^3))
#include <bits/stdc++.h>
using namespace std;

int characterReplacement(string s, int k) {
    int n = s.size();
    int maxi = 0;

    for(int i = 0; i < n; i++) {
        for(int j = i; j < n; j++) {
            vector<int> freq(26, 0);
            int maxFreq = 0;

            for(int x = i; x <= j; x++) {
                freq[s[x] - 'A']++;
                maxFreq = max(maxFreq, freq[s[x] - 'A']);
            }

            int len = j - i + 1;
            if(len - maxFreq <= k) {
                maxi = max(maxi, len);
            }
        }
    }

    return maxi;
}

// BETTER (O(N^2))
int characterReplacementBetter(string s, int k) {
    int n = s.size();
    int maxi = 0;

    for(int i = 0; i < n; i++) {
        vector<int> freq(26, 0);
        int maxFreq = 0;

        for(int j = i; j < n; j++) {
            freq[s[j] - 'A']++;
            maxFreq = max(maxFreq, freq[s[j] - 'A']);

            int len = j - i + 1;
            if(len - maxFreq <= k) {
                maxi = max(maxi, len);
            }
        }
    }

    return maxi;
}

// OPTIMAL (O(N))
int characterReplacementOptimal(string s, int k) {
    vector<int> freq(26, 0);
    int l = 0, maxFreq = 0, maxi = 0;

    for(int r = 0; r < s.size(); r++) {
        freq[s[r] - 'A']++;
        maxFreq = max(maxFreq, freq[s[r] - 'A']);

        while((r - l + 1) - maxFreq > k) {
            freq[s[l] - 'A']--;
            l++;
        }

        maxi = max(maxi, r - l + 1);
    }

    return maxi;
}
